const body = $input.item.json;
const embedding = body.data?.[0]?.embedding;
if (!embedding || !Array.isArray(embedding)) {
  throw new Error('OpenAI embedding failed: ' + JSON.stringify(body));
}
return [{ json: { embedding } }];

const body = $input.item.json;
const matches = body.matches || [];

const results = matches
  .filter(m => m.score > 0.3)
  .map((m, i) => {
    const meta = m.metadata || {};
    return {
      guideline_id: m.id || meta.id || ('result-' + i),
      source: meta.source || 'clinical_guideline',
      title: meta.title || 'Clinical Guideline',
      excerpt: (meta.text || meta._node_content || '').slice(0, 400),
      relevance_score: Math.round((m.score || 0) * 100)
    };
  })
  .filter(r => r.excerpt.length > 0);

const context_block = results
  .map(r => '[' + r.title + '] ' + r.excerpt)
  .join('\n\n');

return [{
  json: {
    retrieved_context: results,
    context_block,
    top_guideline: results[0]?.title || null,
    match_count: results.length
  }
}];
